{
  "learning_outcomes": [
    {
      "unit_name": "Sets and Functions",
      "chapter_name": "Sets and Functions",
      "topic": "Foundational set theory, function properties, and trigonometry",
      "outcomes": [
        "Represent sets using various methods and perform operations like union, intersection, and complementation.",
        "Analyze relations and functions including domain, range, and composition of functions.",
        "Apply trigonometric identities and solve equations involving general solutions."
      ]
    },
    {
      "unit_name": "Algebra",
      "chapter_name": "Algebra",
      "topic": "Advanced algebraic techniques including induction, complex numbers, and series",
      "outcomes": [
        "Apply the Principle of Mathematical Induction to prove statements about natural numbers.",
        "Solve quadratic equations in the complex number system using polar representation.",
        "Graphically solve linear inequalities in two variables.",
        "Determine general and middle terms in binomial expansions.",
        "Calculate sums of special series involving powers of integers."
      ]
    },
    {
      "unit_name": "Coordinate Geometry",
      "chapter_name": "Coordinate Geometry",
      "topic": "Equations of lines and spatial geometry basics",
      "outcomes": [
        "Derive equations of straight lines in normal form, general form, and other standard forms.",
        "Apply the section formula to find coordinates dividing a line segment."
      ]
    },
    {
      "unit_name": "Calculus",
      "chapter_name": "Calculus",
      "topic": "Introduction to differentiation and limits",
      "outcomes": [
        "Apply the chain rule for derivatives of composite functions."
      ]
    },
    {
      "unit_name": "Statistics and Probability",
      "chapter_name": "Statistics and Probability",
      "topic": "Fundamental probability concepts",
      "outcomes": [
        "Define random experiments, outcomes, and sample spaces using set representation."
      ]
    }
  ]
}
